# fix_sidebar_areas.ps1 - Sidebar con areas separadas
Write-Host "Aplicando areas al sidebar..." -ForegroundColor Cyan
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$text = [System.Text.Encoding]::UTF8.GetString($bytes)
[System.IO.File]::WriteAllText((Resolve-Path ".").Path + "\src\components\Sidebar.tsx", $text, [System.Text.Encoding]::UTF8)
Write-Host "Sidebar con areas listo!" -ForegroundColor Green
